proof fn phi_1_bitmask_l0_range(vaddr: usize)
    ensures
        l0_bits!(vaddr) < 512,
{
    assert(((vaddr & bitmask_inc!(39usize,47usize)) >> 39usize) < 512) by (bit_vector);
}

proof fn phi_3_align_to_usize_rounds_down(a: usize, b: usize)
    requires
        b > 0,
        a >= b,
    ensures
        align_to_usize(a, b) <= a,
{
    assert(sub(a, a % b) <= a) by (bit_vector)
        requires b > 0 && a >= b;
}

proof fn phi_4_l3_bits_zero_for_page_aligned(vaddr: usize)
    requires
        vaddr % L2_ENTRY_SIZE as usize == 0,
    ensures
        l3_bits!(vaddr) == 0,
{
    let l2_es = L2_ENTRY_SIZE;
    assert(((vaddr & bitmask_inc!(12usize,20usize)) >> 12usize) == 0) by (bit_vector)
        requires vaddr % l2_es == 0, l2_es == 512 * 4096;
}
